import React from 'react';
import { education } from '../../data';
import './Education.css';

export default function Education() {
  return (
    <section id="education">
      <div className="container">
        <div className="section-tag">05 // Education</div>
        <h2 className="section-title">Academic Background</h2>

        <div className="edu-timeline">
          {education.map((edu, i) => (
            <div className="edu-item reveal" key={i}>
              <div className="edu-icon-col">
                <div className="edu-icon">{edu.icon}</div>
                {i < education.length - 1 && <div className="edu-connector" />}
              </div>
              <div className="edu-card nm-card">
                <div className="edu-card-header">
                  <div>
                    <div className="edu-degree">{edu.degree}</div>
                    <div className="edu-institution">
                      <i className="fas fa-map-marker-alt" /> {edu.institution}
                    </div>
                  </div>
                  <div className="edu-right">
                    <div className="edu-period">
                      <i className="fas fa-calendar" /> {edu.period}
                    </div>
                    <div className="edu-grade">{edu.grade}</div>
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
